mapper.select:
select distinct s.stock_id, p.product_id, p.product_name, p.expiration_date, s.stock_amount, i.inbound_date from stock_table s join product p on s.product_id = p.product_id join inbound_table i on i.product_id = p.product_id join business_table b on b.business_id = p.business_id WHERE b.user_id = #{userId} and i.inbound_date is not null
AND p.product_name LIKE CONCAT('%', #{productName}, '%')
LIMIT #{limit} OFFSET #{offset}
